"""Circle packing: 26 hex rows with boundary expansion."""
import numpy as np

def construct_packing():
    n = 26
    row_counts = [5, 4, 5, 4, 5, 3]
    r = 1.0 / (2 + 5 * np.sqrt(3)) * 0.99995
    dy = r * np.sqrt(3)
    centers = []
    y = r
    for c in row_counts:
        if c == 5:
            xs = [r + 2*r*k for k in range(5)]
        elif c == 4:
            xs = [2*r + 2*r*k for k in range(4)]
        else:
            xs = [4*r + 2*r*k for k in range(3)]
        for x in xs:
            centers.append([x, y])
        y += dy
    centers = np.array(centers[:n], dtype=float)
    radii = np.full(n, r)
    # Expand each circle to touch wall or nearest neighbor
    for i in range(n):
        cx, cy = centers[i]
        max_r = min(cx, cy, 1-cx, 1-cy)
        for j in range(n):
            if j == i: continue
            d = np.hypot(cx-centers[j,0], cy-centers[j,1])
            max_r = min(max_r, d - radii[j])
        radii[i] = max(radii[i], max_r * 0.99999)
    return centers, radii, float(np.sum(radii))
# EVOLVE-BLOCK-END

def run_packing():
    return construct_packing()

